"use client";

import * as React from "react";

import { cn } from "@/lib/utils";
import { clamp01, usePrefersReducedMotion } from "@/components/experience/experience-runtime";

export type ScrollStackProps = React.ComponentProps<"section"> & {
  label: string;
  /** Each direct child becomes one stacked card. */
  children: React.ReactNode;
  /** Sticky offset of the first card from the viewport top, in pixels. */
  topOffset?: number;
  /** Extra sticky offset per card so covered headers stay visible, in pixels. */
  peek?: number;
  /** Vertical rhythm between cards while they are still in flow, in pixels. */
  gap?: number;
  /** How much a fully covered card scales down. */
  scaleStep?: number;
  /** How much a fully covered card darkens (0..1). */
  dim?: number;
  itemClassName?: string;
};

/**
 * Stacking cards: each card pins below the viewport top and the next one
 * slides over it, gently scaling and dimming what it covers — the classic
 * services/process pattern. Everything is derived from live measurements, so
 * cards can have any height, and scrolling back replays the stack in reverse.
 * Reduced motion renders a plain vertical list.
 */
export function ScrollStack({
  children,
  className,
  dim = 0.35,
  gap = 24,
  itemClassName,
  label,
  peek = 16,
  scaleStep = 0.05,
  topOffset = 96,
  ...props
}: ScrollStackProps) {
  const rootRef = React.useRef<HTMLElement>(null);
  const reducedMotion = usePrefersReducedMotion();
  const items = React.Children.toArray(children);

  React.useEffect(() => {
    const root = rootRef.current;
    if (!root || reducedMotion) return;
    let frame = 0;
    let onScreen = true;
    const cards = Array.from(root.querySelectorAll<HTMLElement>("[data-scroll-stack-item]"));
    const inners = cards.map((card) => card.querySelector<HTMLElement>("[data-scroll-stack-inner]"));
    const update = () => {
      cancelAnimationFrame(frame);
      frame = requestAnimationFrame(() => {
        if (!onScreen) return;
        for (let index = 0; index < cards.length - 1; index += 1) {
          const inner = inners[index];
          const next = cards[index + 1];
          if (!inner || !next) continue;
          const rect = inner.getBoundingClientRect();
          // 0 while the next card is still below, 1 once it fully covers this one.
          const covered = clamp01(1 - (next.getBoundingClientRect().top - rect.top) / Math.max(1, rect.height));
          inner.style.transform = covered > 0 ? `scale(${(1 - covered * scaleStep).toFixed(4)})` : "";
          inner.style.filter = covered > 0 && dim > 0 ? `brightness(${(1 - covered * dim).toFixed(3)})` : "";
        }
      });
    };
    const intersectionObserver = new IntersectionObserver(
      ([entry]) => {
        onScreen = Boolean(entry?.isIntersecting);
        if (onScreen) update();
      },
      { rootMargin: "20% 0px" },
    );
    intersectionObserver.observe(root);
    const resizeObserver = new ResizeObserver(update);
    resizeObserver.observe(root);
    window.addEventListener("scroll", update, { passive: true });
    update();
    return () => {
      cancelAnimationFrame(frame);
      intersectionObserver.disconnect();
      resizeObserver.disconnect();
      window.removeEventListener("scroll", update);
    };
  }, [dim, reducedMotion, scaleStep, items.length]);

  if (reducedMotion) {
    return (
      <section ref={rootRef} aria-label={label} data-scroll-stack data-static className={className} {...props}>
        <div className="flex flex-col" style={{ gap }}>
          {items.map((item, index) => (
            <div key={index} className={itemClassName}>
              {item}
            </div>
          ))}
        </div>
      </section>
    );
  }

  return (
    <section ref={rootRef} aria-label={label} data-scroll-stack className={className} {...props}>
      {items.map((item, index) => (
        <div
          key={index}
          data-scroll-stack-item
          className="sticky"
          style={{ top: topOffset + index * peek, marginTop: index === 0 ? 0 : gap }}
        >
          <div data-scroll-stack-inner className={cn("origin-top will-change-transform", itemClassName)}>
            {item}
          </div>
        </div>
      ))}
    </section>
  );
}

"use client";

import * as React from "react";

const subscribeToHydration = () => () => undefined;

export function useHydrated() {
  return React.useSyncExternalStore(subscribeToHydration, () => true, () => false);
}

export function useMediaQuery(query: string, serverValue = false) {
  const subscribe = React.useCallback(
    (onChange: () => void) => {
      const media = window.matchMedia(query);
      media.addEventListener("change", onChange);
      return () => media.removeEventListener("change", onChange);
    },
    [query],
  );
  const getSnapshot = React.useCallback(() => window.matchMedia(query).matches, [query]);
  return React.useSyncExternalStore(subscribe, getSnapshot, () => serverValue);
}

/**
 * Hydration-safe reduced-motion preference: false on the server and during
 * hydration, then live. Replaces the repeated `mounted && useReducedMotion()`
 * pattern.
 */
export function usePrefersReducedMotion() {
  return useMediaQuery("(prefers-reduced-motion: reduce)");
}

/** True on touch-first devices; use to swap pointer effects for static or rail modes. */
export function useCoarsePointer() {
  return useMediaQuery("(pointer: coarse)");
}

/** True only when a hover-capable precise pointer is present. */
export function useFinePointer() {
  return useMediaQuery("(hover: hover) and (pointer: fine)");
}

export function clamp01(value: number) {
  return Math.min(1, Math.max(0, value));
}

export function mix(from: number, to: number, amount: number) {
  return from + (to - from) * amount;
}

export function damp(current: number, target: number, smoothing: number, deltaSeconds: number) {
  return mix(current, target, 1 - Math.exp(-Math.max(0.01, smoothing) * deltaSeconds));
}

/** Returns the frames sorted by `at`, reusing the input when it is already ordered. */
export function sortKeyframes<T extends { at: number }>(frames: T[]): T[] {
  for (let index = 1; index < frames.length; index += 1) {
    if (frames[index - 1]!.at > frames[index]!.at) {
      return [...frames].sort((left, right) => left.at - right.at);
    }
  }
  return frames;
}

export function resolveKeyframes<T extends { at: number }>(
  frames: T[],
  progress: number,
): { from: T; to: T; mix: number } {
  if (frames.length === 0) throw new Error("Experience keyframes cannot be empty.");
  const sorted = sortKeyframes(frames);
  if (progress <= sorted[0]!.at) return { from: sorted[0]!, to: sorted[0]!, mix: 0 };
  for (let index = 0; index < sorted.length - 1; index += 1) {
    const from = sorted[index]!;
    const to = sorted[index + 1]!;
    if (progress <= to.at) {
      const span = Math.max(0.0001, to.at - from.at);
      return { from, to, mix: clamp01((progress - from.at) / span) };
    }
  }
  const final = sorted.at(-1)!;
  return { from: final, to: final, mix: 0 };
}

export function supportsWebGL() {
  try {
    const canvas = document.createElement("canvas");
    return Boolean(
      canvas.getContext("webgl2", { failIfMajorPerformanceCaveat: true })
      || canvas.getContext("webgl", { failIfMajorPerformanceCaveat: true }),
    );
  } catch {
    return false;
  }
}
